import numpy as np

def per_channel_scale(W: np.ndarray, n_bits: int) -> np.ndarray:
    q_max = 2 ** (n_bits - 1) - 1
    max_abs = np.max(np.abs(W), axis=1)
    return max_abs / q_max

def per_channel_quantize(W: np.ndarray, scales: np.ndarray, n_bits: int) -> np.ndarray:
    q_min = -(2 ** (n_bits - 1))
    q_max = 2 ** (n_bits - 1) - 1
    scales_col = scales[:, np.newaxis]
    q = np.round(W / scales_col)
    return np.clip(q, q_min, q_max).astype(np.int32)

def per_channel_dequantize(Q: np.ndarray, scales: np.ndarray) -> np.ndarray:
    return Q.astype(np.float32) * scales[:, np.newaxis]
